import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const BORDER_COLORS = [
  '#e63946', '#457b9d', '#2a9d8f', '#f4a261', '#e76f51'
];

export default function Header({ onlineUsers = [] }) {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [showAllOnline, setShowAllOnline] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const wrapperRef = useRef(null);
  const onlineListRef = useRef(null);

  // Fecha o popover ao clicar fora
  useEffect(() => {
    function handleClickOutside(event) {
      if (
        onlineListRef.current &&
        !onlineListRef.current.contains(event.target)
      ) {
        setShowAllOnline(false);
      }
      if (
        wrapperRef.current &&
        !wrapperRef.current.contains(event.target)
      ) {
        setDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const others = onlineUsers.filter(u => u.id !== user?.id);
  const firstThree = others.slice(0, 3);
  const moreCount = others.length - 3;

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-white shadow flex items-center justify-between px-6 z-50">
      <h1 className="text-xl font-bold text-[#152A3F]">PoliUB Atendimentos</h1>
      <div className="flex items-center space-x-4">
        <div className="flex items-center space-x-1 relative">
          {/* Avatar do próprio usuário */}
          {user && (
            <img
              src={
                user.avatar_url ||
                `https://ui-avatars.com/api/?name=${encodeURIComponent(user.nome)}&background=ccc`
              }
              alt={user.nome}
              title={user.nome}
              className="w-8 h-8 rounded-full"
              style={{ border: `2px solid ${BORDER_COLORS[0]}` }}
            />
          )}

          {/* Avatares dos 3 primeiros */}
          {firstThree.map((u, i) => (
            <img
              key={u.id}
              src={
                u.avatar_url ||
                `https://ui-avatars.com/api/?name=${encodeURIComponent(u.nome)}&background=ccc`
              }
              alt={u.nome}
              title={u.nome}
              className="w-8 h-8 rounded-full"
              style={{
                border: `2px solid ${BORDER_COLORS[(i + 1) % BORDER_COLORS.length]}`
              }}
            />
          ))}

          {/* Bolinha "+N" para expandir */}
          {moreCount > 0 && (
            <button
              className="w-8 h-8 rounded-full bg-gray-100 border border-gray-300 text-xs font-bold flex items-center justify-center hover:bg-gray-200"
              onClick={() => setShowAllOnline(val => !val)}
              title="Mostrar todos online"
              style={{ minWidth: '2rem' }}
            >+{moreCount}</button>
          )}

          {/* Popover: todos online */}
          {showAllOnline && (
            <div
              ref={onlineListRef}
              className="absolute right-0 mt-12 bg-white border border-gray-200 rounded-lg shadow-lg p-2 min-w-[190px] z-50"
            >
              <div className="font-semibold mb-1 text-gray-700">Online:</div>
              <ul>
                {others.map(u => (
                  <li key={u.id} className="flex items-center gap-2 py-1">
                    <img
                      src={
                        u.avatar_url ||
                        `https://ui-avatars.com/api/?name=${encodeURIComponent(u.nome)}&background=ccc`
                      }
                      alt={u.nome}
                      className="w-6 h-6 rounded-full border border-gray-200"
                    />
                    <span className="text-gray-800 text-sm">{u.nome}</span>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>

        {/* Botão/profile dropdown */}
        <div ref={wrapperRef} className="relative">
          <button
            onClick={() => setDropdownOpen(v => !v)}
            className="rounded-full focus:outline-none"
          >
            {/* ícone de perfil simplificado */}
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32" width="42px" height="42px">
              <circle cx="16" cy="12" r="6" fill="#0095DA" />
              <ellipse cx="16" cy="26" rx="10" ry="6" fill="#c3e3f8" />
            </svg>
          </button>
          {dropdownOpen && (
            <ul className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg">
              <li className="px-4 py-2 text-gray-700 font-medium border-b border-gray-100">
                {user?.nome || 'Usuário'}
              </li>
              <li>
                <button
                  onClick={() => { setDropdownOpen(false); navigate('/perfil'); }}
                  className="w-full text-left px-4 py-2 hover:bg-gray-100 text-gray-700"
                >
                  Meu Perfil
                </button>
              </li>
              <li>
                <button
                  onClick={() => { setDropdownOpen(false); logout(); navigate('/login', { replace: true }); }}
                  className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-600"
                >
                  Sair
                </button>
              </li>
            </ul>
          )}
        </div>
      </div>
    </header>
  );
}
